          },
        ],
      });
      // Sword base: 100G, first insurance +10% = 110G, processing fee +5G = 115G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it.todo("should quote a single amulet for a new customer");
    it.todo("should quote multiple items summing their base premiums");
    it.todo("should quote a single component at 25G base premium");
    it.todo("should quote a building block of 3 alike components at 60G special premium");
    it.todo("should apply 50% cursed-item surcharge to the item base premium");
    it.todo("should apply 30% surcharge for enchantment level 5 or higher");
    it.todo("should apply 20% loyalty discount for customers with 2 or more years");
    it.todo("should apply 15% after-first-contract discount on the second quote in a scenario");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible to a basic claim");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment level 8 or higher");
    it.todo("should fully reimburse damage to dragon material items");
  });

  describe("CLI", () => {
    it.todo("should read JSON from stdin and write results JSON to stdout");
  });
});

