interface ScenarioResult {
  results: Array<{ premium?: number; payout?: number; remainingCap?: number }>;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export function processScenario(scenario: any): ScenarioResult {
  const step = scenario.steps[0];
  const item = step.items[0];
  const basePremium = BASE_PREMIUMS[item.type];
  const premium = Math.ceil(basePremium * 1.1) + 5;
  return { results: [{ premium }] };
}

