import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

function quote(items: any[], yearsWithMHPCO = 0) {
  return processScenario({
    customer: { yearsWithMHPCO },
    steps: [{ op: "quote" as const, items }],
  });
}

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should quote a single sword for a new customer with first-insurance surcharge and processing fee", () => {
      const result = quote([
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
      ]);
      // Sword base: 100G, first insurance +10% = 110G, processing fee +5G = 115G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should quote a single amulet for a new customer", () => {
      const result = quote([
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ]);
      // Amulet base: 60G, first insurance +10% = 66G, processing fee +5G = 71G
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should quote multiple items summing their base premiums", () => {
      const result = quote([
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
        { type: "amulet", material: "silver", enchantment: 0, cursed: false },
      ]);
      // Sword 100G + Amulet 60G = 160G, first insurance +10% = 176G, fee +5G = 181G
      expect(result.results[0]).toEqual({ premium: 181 });
    });
    it("should quote a single component at 25G base premium", () => {
      const result = quote([
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
      ]);
      // Rune (component) base: 25G, first insurance +10% = 27.5 → ceil 28G, fee +5G = 33G
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should quote a building block of 3 alike components at 60G special premium", () => {
      const result = quote([
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
      ]);
      // 3 alike runes = building block at 60G, first insurance +10% = 66G, fee +5G = 71G
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should apply 50% cursed-item surcharge to the item base premium", () => {
      const result = quote([
        { type: "sword", material: "steel", enchantment: 0, cursed: true },
      ]);
      // Sword base: 100G, cursed +50% = 150G, first insurance +10% = 165G, fee +5G = 170G
      expect(result.results[0]).toEqual({ premium: 170 });
    });
    it("should apply 30% surcharge for enchantment level 5 or higher", () => {
      const result = quote([
        { type: "sword", material: "steel", enchantment: 5, cursed: false },
      ]);
      // Sword base: 100G, enchantment ≥5 +30% = 130G, first insurance +10% = 143G, fee +5G = 148G
      expect(result.results[0]).toEqual({ premium: 148 });
    });
    it("should apply 20% loyalty discount for customers with 2 or more years", () => {
      const result = quote([
        { type: "sword", material: "steel", enchantment: 0, cursed: false },
      ], 3);
      // Sword base: 100G, after-first -15% = 85G, loyalty -20% = 68G, fee +5G = 73G
      expect(result.results[0]).toEqual({ premium: 73 });
    });
    it("should apply 15% after-first-contract discount on the second quote in a scenario", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // First quote: first insurance +10% → 115G
      expect(result.results[0]).toEqual({ premium: 115 });
      // Second quote: after-first -15% → 100 * 0.85 = 85, ceil = 85 + 5 = 90G
      expect(result.results[1]).toEqual({ premium: 90 });
    });
  });

  describe("Processing a claim", () => {
    it("should apply 100G deductible to a basic claim", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
          {
            op: "claim" as const,
            policy: 0,
            incident: {
              cause: "fire",
              damages: [{ itemType: "amulet", amount: 200 }],
            },
          },
        ],
      });
      // Amulet insurance value: 600G, cap: 1200G
      // Damage 200G - deductible 100G = payout 100G, remaining cap 1100G
      expect(result.results[1]).toEqual({ payout: 100, remainingCap: 1100 });
    });
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment level 8 or higher");
    it.todo("should fully reimburse damage to dragon material items");
  });

  describe("CLI", () => {
    it.todo("should read JSON from stdin and write results JSON to stdout");
  });
});

interface ScenarioResult {
  results: Array<{ premium?: number; payout?: number; remainingCap?: number }>;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);
const BUILDING_BLOCK_SIZE = 3;
const BUILDING_BLOCK_PREMIUM = 60;
const PROCESSING_FEE = 5;

function calculateMainItemPremium(item: any): number {
  let premium = BASE_PREMIUMS[item.type];
  if (item.cursed) {
    premium = premium * 3 / 2;
  }
  if (item.enchantment >= 5) {
    premium = premium * 13 / 10;
  }
  return premium;
}

function calculateItemPremiums(items: any[]): number {
  const componentCounts: Record<string, number> = {};
  let mainItemPremium = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      mainItemPremium += calculateMainItemPremium(item);
    }
  }

  let componentPremium = 0;
  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
    const remaining = count % BUILDING_BLOCK_SIZE;
    componentPremium += blocks * BUILDING_BLOCK_PREMIUM + remaining * BASE_PREMIUMS[type];
  }

  return mainItemPremium + componentPremium;
}

function applyCustomerModifiers(premium: number, customer: any, isFirstInsurance: boolean): number {
  let adjusted = premium;
  if (isFirstInsurance) {
    adjusted = adjusted * 11 / 10;
  } else {
    adjusted = adjusted * 17 / 20;
    if (customer.yearsWithMHPCO >= 2) {
      adjusted = adjusted * 4 / 5;
    }
  }
  return adjusted;
}

function processQuote(step: any, customer: any, isFirstInsurance: boolean): { premium: number } {
  const itemPremiums = calculateItemPremiums(step.items);
  const adjusted = applyCustomerModifiers(itemPremiums, customer, isFirstInsurance);
  const premium = Math.ceil(adjusted) + PROCESSING_FEE;
  return { premium };
}

export function processScenario(scenario: any): ScenarioResult {
  const customer = scenario.customer;
  const results: ScenarioResult["results"] = [];
  let quoteCount = 0;

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const isFirstInsurance = customer.yearsWithMHPCO === 0 && quoteCount === 0;
      results.push(processQuote(step, customer, isFirstInsurance));
      quoteCount++;
    }
  }

  return { results };
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    include: ['src/**/*.spec.ts'],
    globals: true,
    coverage: {
      provider: 'v8',
      reporter: ['json-summary', 'text'],
      include: ['src/**/*.ts'],
      exclude: ['src/**/*.spec.ts'],
    },
  },
});

