1	interface ScenarioResult {
2	  results: Array<{ premium?: number; payout?: number; remainingCap?: number }>;
3	}
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  rune: 25,
9	};
10	
11	const INSURANCE_VALUES: Record<string, number> = {
12	  sword: 1000,
13	  amulet: 600,
14	  staff: 800,
15	  potion: 400,
16	  rune: 250,
17	};
18	
19	const DEDUCTIBLE = 100;
20	
21	const COMPONENT_TYPES = new Set(["rune"]);
22	const BUILDING_BLOCK_SIZE = 3;
23	const BUILDING_BLOCK_PREMIUM = 60;
24	const PROCESSING_FEE = 5;
25	
26	function calculateMainItemPremium(item: any): number {
27	  let premium = BASE_PREMIUMS[item.type];
28	  if (item.cursed) {
29	    premium = premium * 3 / 2;
30	  }
31	  if (item.enchantment >= 5) {
32	    premium = premium * 13 / 10;
33	  }
34	  return premium;
35	}
36	
37	function calculateItemPremiums(items: any[]): number {
38	  const componentCounts: Record<string, number> = {};
39	  let mainItemPremium = 0;
40	
41	  for (const item of items) {
42	    if (COMPONENT_TYPES.has(item.type)) {
43	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
44	    } else {
45	      mainItemPremium += calculateMainItemPremium(item);
46	    }
47	  }
48	
49	  let componentPremium = 0;
50	  for (const type of Object.keys(componentCounts)) {
51	    const count = componentCounts[type];
52	    const blocks = Math.floor(count / BUILDING_BLOCK_SIZE);
53	    const remaining = count % BUILDING_BLOCK_SIZE;
54	    componentPremium += blocks * BUILDING_BLOCK_PREMIUM + remaining * BASE_PREMIUMS[type];
55	  }
56	
57	  return mainItemPremium + componentPremium;
58	}
59	
60	function applyCustomerModifiers(premium: number, customer: any, isFirstInsurance: boolean): number {
61	  let adjusted = premium;
62	  if (isFirstInsurance) {
63	    adjusted = adjusted * 11 / 10;
64	  } else {
65	    adjusted = adjusted * 17 / 20;
66	    if (customer.yearsWithMHPCO >= 2) {
67	      adjusted = adjusted * 4 / 5;
68	    }
69	  }
70	  return adjusted;
71	}
72	
73	function processQuote(step: any, customer: any, isFirstInsurance: boolean): { premium: number } {
74	  const itemPremiums = calculateItemPremiums(step.items);
75	  const adjusted = applyCustomerModifiers(itemPremiums, customer, isFirstInsurance);
76	  const premium = Math.ceil(adjusted) + PROCESSING_FEE;
77	  return { premium };
78	}
79	
80	function calculateInsuranceSum(items: any[]): number {
81	  let sum = 0;
82	  for (const item of items) {
83	    sum += INSURANCE_VALUES[item.type] || 0;
84	  }
85	  return sum;
86	}
87	
88	function processClaim(step: any, policy: { remainingCap: number }): { payout: number; remainingCap: number } {
89	  let totalDamage = 0;
90	  for (const damage of step.incident.damages) {
91	    totalDamage += damage.amount;
92	  }
93	  const uncappedPayout = Math.max(0, Math.floor(totalDamage - DEDUCTIBLE));
94	  const payout = Math.min(uncappedPayout, policy.remainingCap);
95	  policy.remainingCap -= payout;
96	  return { payout, remainingCap: policy.remainingCap };
97	}
98	
99	export function processScenario(scenario: any): ScenarioResult {
100	  const customer = scenario.customer;
101	  const results: ScenarioResult["results"] = [];
102	  let quoteCount = 0;
103	  const policies: Array<{ items: any[]; insuranceSum: number; remainingCap: number }> = [];
104	
105	  for (const step of scenario.steps) {
106	    if (step.op === "quote") {
107	      const isFirstInsurance = customer.yearsWithMHPCO === 0 && quoteCount === 0;
108	      results.push(processQuote(step, customer, isFirstInsurance));
109	      const insuranceSum = calculateInsuranceSum(step.items);
110	      policies.push({ items: step.items, insuranceSum, remainingCap: insuranceSum * 2 });
111	      quoteCount++;
112	    } else if (step.op === "claim") {
113	      results.push(processClaim(step, policies[step.policy]));
114	    }
115	  }
116	
117	  return { results };
118	}
