  let totalDamage = 0;
  for (const damage of step.incident.damages) {
    totalDamage += damage.amount;
  }
  const uncappedPayout = Math.max(0, Math.floor(totalDamage - DEDUCTIBLE));
  const payout = Math.min(uncappedPayout, policy.remainingCap);
